def validate_xml_document(file_input, max_file_size=10*1024*1024, allowed_extensions=None):
    """
    Securely reads and validates an XML document uploaded by a user.
    
    Args:
        file_input: File object, file path string, or bytes
        max_file_size: Maximum allowed file size in bytes (default 10MB)
        allowed_extensions: List of allowed file extensions (default ['.xml'])
    
    Returns:
        dict: {
            'valid': bool,
            'root': ElementTree root element if valid,
            'errors': list of error messages,
            'warnings': list of warning messages
        }
    """
    if allowed_extensions is None:
        allowed_extensions = ['.xml']
    
    result = {
        'valid': False,
        'root': None,
        'errors': [],
        'warnings': []
    }
    
    try:
        # Handle different input types
        if isinstance(file_input, str):
            # File path
            if not os.path.exists(file_input):
                result['errors'].append("File does not exist")
                return result
            
            # Check file extension
            _, ext = os.path.splitext(file_input)
            if ext.lower() not in allowed_extensions:
                result['errors'].append(f"Invalid file extension. Allowed: {allowed_extensions}")
                return result
            
            # Check file size
            file_size = os.path.getsize(file_input)
            if file_size > max_file_size:
                result['errors'].append(f"File size ({file_size} bytes) exceeds maximum allowed ({max_file_size} bytes)")
                return result
            
            # Read file content
            with open(file_input, 'rb') as f:
                xml_content = f.read()
        
        elif isinstance(file_input, bytes):
            # Bytes input
            if len(file_input) > max_file_size:
                result['errors'].append(f"Content size ({len(file_input)} bytes) exceeds maximum allowed ({max_file_size} bytes)")
                return result
            xml_content = file_input
        
        elif hasattr(file_input, 'read'):
            # File-like object
            if hasattr(file_input, 'name'):
                _, ext = os.path.splitext(file_input.name)
                if ext.lower() not in allowed_extensions:
                    result['errors'].append(f"Invalid file extension. Allowed: {allowed_extensions}")
                    return result
            
            # Read content with size limit
            xml_content = file_input.read(max_file_size + 1)
            if len(xml_content) > max_file_size:
                result['errors'].append(f"File size exceeds maximum allowed ({max_file_size} bytes)")
                return result
        
        else:
            result['errors'].append("Invalid input type. Expected file path, bytes, or file object")
            return result
        
        # Validate that content is not empty
        if not xml_content or len(xml_content.strip()) == 0:
            result['errors'].append("XML content is empty")
            return result
        
        # Check for XML declaration and basic structure
        xml_str = xml_content.decode('utf-8', errors='replace').strip()
        
        # Warn if no XML declaration
        if not xml_str.startswith('<?xml'):
            result['warnings'].append("XML declaration is missing")
        
        # Parse XML using defusedxml to prevent XXE and other attacks
        try:
            root = DefusedET.fromstring(xml_content)
        except DefusedET.ParseError as e:
            result['errors'].append(f"XML parsing error: {str(e)}")
            return result
        except Exception as e:
            result['errors'].append(f"Error parsing XML: {str(e)}")
            return result
        
        # Additional validation checks
        if root is None:
            result['errors'].append("Failed to parse XML root element")
            return result
        
        # Check for excessively deep nesting (potential DoS)
        max_depth = 100
        def check_depth(element, current_depth=0):
            if current_depth > max_depth:
                return False
            for child in element:
                if not check_depth(child, current_depth + 1):
                    return False
            return True
        
        if not check_depth(root):
            result['errors'].append(f"XML nesting depth exceeds maximum allowed ({max_depth})")
            return result
        
        # Check for excessive number of elements (potential DoS)
        max_elements = 100000
        element_count = len(list(root.iter()))
        if element_count > max_elements:
            result['errors'].append(f"XML contains too many elements ({element_count}), maximum allowed: {max_elements}")
            return result
        
        # If we got here, validation passed
        result['valid'] = True
        result['root'] = root
        
    except UnicodeDecodeError as e:
        result['errors'].append(f"Invalid encoding: {str(e)}")
    except MemoryError:
        result['errors'].append("File too large to process in memory")
    except Exception as e:
        result['errors'].append(f"Unexpected error: {str(e)}")
    
    return result


def validate_xml_against_schema(xml_root, schema_file=None):
    """
    Validates XML against an XSD schema if provided.
    
    Args:
        xml_root: ElementTree root element
        schema_file: Path to XSD schema file
    
    Returns:
        dict: {'valid': bool, 'errors': list}
    """
    result = {'valid': False, 'errors': []}
    
    try:
        from lxml import etree
        
        if schema_file and os.path.exists(schema_file):
            with open(schema_file, 'rb') as f:
                schema_root = etree.XML(f.read())
            schema = etree.XMLSchema(schema_root)
            
            # Convert ElementTree to lxml
            xml_string = ET.tostring(xml_root, encoding='utf-8')
            xml_doc = etree.fromstring(xml_string)
            
            if schema.validate(xml_doc):
                result['valid'] = True
            else:
                for error in schema.error_log:
                    result['errors'].append(f"Line {error.line}: {error.message}")
        else:
            result['errors'].append("Schema file not found or not provided")
    
    except ImportError:
        result['errors'].append("lxml library required for schema validation")
    except Exception as e:
        result['errors'].append(f"Schema validation error: {str(e)}")
    
    return result